// 置信度评估和阈值检查
const diagnosisData = $json;
const confidenceScore = diagnosisData.confidenceScore || 0;
const threshold = parseInt(process.env.CONFIDENCE_THRESHOLD || '70');

// 多维度置信度计算
const baseConfidence = confidenceScore;
const historicalAccuracy = diagnosisData.historicalAccuracy || 85;
const userSatisfaction = diagnosisData.userSatisfaction || 4.2;

// 综合置信度计算
const compositeConfidence = 
  (baseConfidence * 0.6) + 
  (historicalAccuracy * 0.3) + 
  (userSatisfaction * 10 * 0.1); // 满意度转换为0-100分

const shouldEscalate = compositeConfidence < threshold;

// 问题紧急程度评估
const urgencyMap = {
  'critical': 3,
  'high': 2,
  'medium': 1,
  'low': 0
};

const urgencyLevel = urgencyMap[diagnosisData.urgency] || 1;

return [{
  json: {
    ...diagnosisData,
    compositeConfidence: Math.round(compositeConfidence),
    shouldEscalate: shouldEscalate,
    urgencyLevel: urgencyLevel,
    escalationReason: shouldEscalate ? 'low_confidence' : 'none',
    evaluatedAt: new Date().toISOString()
  }
}];

// 条件分支：只有在需要转人工时才继续
const evaluation = $json;

if (evaluation.shouldEscalate) {
  return [{
    json: evaluation
  }];
} else {
  // 不需要转人工，直接返回结果
  return [{
    json: {
      success: true,
      message: 'AI诊断置信度足够，无需转人工',
      diagnosisId: evaluation.diagnosisId,
      confidence: evaluation.compositeConfidence
    }
  }];
}

// 智能工程师分配算法
const ticketData = $node['TicketCreator'].json;
const urgency = $json.urgencyLevel;

// 简化的工程师分配逻辑
const engineers = [
  { id: 'ENG001', name: '张工程师', skills: ['hardware', 'mobile'], load: 2 },
  { id: 'ENG002', name: '李工程师', skills: ['software', 'mobile'], load: 1 },
  { id: 'ENG003', name: '王工程师', skills: ['hardware', 'computer'], load: 3 }
];

// 根据问题类型和工程师技能匹配
const issueType = ticketData.deviceInfo.issue.includes('battery') ? 'hardware' : 'software';

// 找到最适合的工程师
let assignedEngineer = engineers[0];
let minLoad = Infinity;

engineers.forEach(engineer => {
  const hasSkill = engineer.skills.includes(issueType);
  const isAvailable = engineer.load < 3;

  if (hasSkill && isAvailable && engineer.load < minLoad) {
    minLoad = engineer.load;
    assignedEngineer = engineer;
  }
});

// 紧急情况下的快速分配
if (urgency >= 2) {
  assignedEngineer = engineers.find(e => e.load <= 2) || assignedEngineer;
}

return [{
  json: {
    ticketId: ticketData.ticketId,
    assignedEngineer: {
      id: assignedEngineer.id,
      name: assignedEngineer.name
    },
    assignmentReason: `技能匹配(${issueType}) + 负载均衡`,
    estimatedResponseTime: urgency >= 2 ? '15分钟' : '30分钟'
  }
}];

// 错误处理和补偿机制
const inputData = $node['AIEscalationWebhook'].json;
const evaluation = $node['ConfidenceEvaluator'].json;
const ticketCreation = $node['CreateTicket'].json;
const notifications = {
  wechat: $node['WechatNotification'].json,
  dingtalk: $node['DingtalkNotification'].json,
  user: $node['UserNotification'].json
};

// 检查各步骤执行情况
const stepStatus = {
  confidenceEvaluated: evaluation.shouldEscalate !== undefined,
  ticketCreated: ticketCreation && ticketCreation.success,
  engineerAssigned: $json.assignedEngineer !== undefined,
  notificationsSent: Object.values(notifications).every(n => n && n.success)
};

const hasFailures = Object.values(stepStatus).some(status => status === false);

if (hasFailures) {
  const failedSteps = Object.entries(stepStatus)
    .filter(([step, status]) => status === false)
    .map(([step]) => step);

  console.error('AI escalation process failed steps:', failedSteps);

  // 记录失败信息用于后续处理
  return [{
    json: {
      success: false,
      escalationId: $node['ResultAggregator'].json.escalationId,
      diagnosisId: inputData.diagnosisId,
      failedSteps: failedSteps,
      requiresManualIntervention: failedSteps.includes('ticketCreated'),
      fallbackAction: 'manual_ticket_creation_required'
    }
  }];
}

// 所有步骤成功完成
return [{
  json: {
    success: true,
    escalationId: $node['ResultAggregator'].json.escalationId,
    ticketId: $node['TicketCreator'].json.ticketId,
    assignedEngineer: $json.assignedEngineer,
    notifications: stepStatus.notificationsSent
  }
}];
